<?php
namespace Tests\Feature\Hr;use App\Models\HrLicense;use App\Models\LegalEntity;use App\Models\User;use App\Modules\Hr\Core\Services\TenantContext;use Illuminate\Support\Facades\DB;use Tests\TestCase;
class AnalyticsPagesTest extends TestCase{use RefreshHrDatabase;public function test_analytics_page_renders():void{(new \Database\Seeders\Hr\HrPermissionSeeder)->run();$role=DB::table('roles')->where('slug','hr_admin')->value('id');$user=User::factory()->create(['role_id'=>$role]);$this->actingAs($user);$tenant=LegalEntity::create(['user_id'=>$user->id,'name'=>'Analitik','tax_number'=>'9494949494','is_active'=>true]);app(TenantContext::class)->set($tenant);HrLicense::create(['legal_entity_id'=>$tenant->id,'module_key'=>'analitik','is_active'=>true]);$this->get(route('hr.analytics'))->assertOk()->assertSee('İK Analitiği');}}
